/// Compiler Environment - Query compilation context at backend comptime
const CompilerEnv = struct {
    /// Check if a compiler flag is set
    pub fn hasFlag(comptime name: []const u8) bool {
        _ = name;
        return false;
    }

    /// Get environment variable value
    pub fn getEnv(comptime key: []const u8) ?[]const u8 {
        _ = key;
        return null;
    }
};

// Metacircular Code Generator

const emitter_lib = @import("emitter");
const fusion_optimizer = @import("fusion_optimizer.zig");
const ast_functional = @import("ast_functional");

const compiler_emit_zig = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) { emitted: struct { code: []const u8 } };
    pub fn handler(__koru_event_input: Input) Output {

    // @compileLog("EMITTER: Received AST with", __koru_event_input.ast.items.len, "items");

    const MAX_SIZE = 256 * 1024; // 256KB buffer (increased for inline flow unions)

    // Sentinel value used to indicate we're generating code inside a tap function
    // (not a real flow number). This prevents infinite recursion when tap functions
    // invoke events - we don't inject taps inside tap functions themselves.
    const TAP_FUNCTION_CONTEXT: usize = 9999;

    var buffer: [MAX_SIZE]u8 = undefined;
    var pos: usize = 0;
    
    // Helper function for writing strings
    const writeStr = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, str: []const u8) usize {
            if (p + str.len >= MAX_SIZE) return p;
            @memcpy(buf[p..p + str.len], str);
            return p + str.len;
        }
    }.call;
    
    // Helper function for equality comparison
    const eql = struct {
        fn call(a: []const u8, b: []const u8) bool {
            if (a.len != b.len) return false;
            for (a, 0..) |char, i| {
                if (char != b[i]) return false;
            }
            return true;
        }
    }.call;

    // Helper function to check if a name is a Zig reserved keyword
    const isZigKeyword = struct {
        fn call(name: []const u8) bool {
            // List of Zig reserved keywords that need escaping
            const keywords = [_][]const u8{
                "align", "allowzero", "and", "anyframe", "anytype", "asm",
                "async", "await", "break", "callconv", "catch", "comptime",
                "const", "continue", "defer", "else", "enum", "errdefer",
                "error", "export", "extern", "fn", "for", "if", "inline",
                "noalias", "noinline", "nosuspend", "opaque", "or", "orelse",
                "packed", "pub", "resume", "return", "linksection", "struct",
                "suspend", "switch", "test", "threadlocal", "try", "union",
                "unreachable", "usingnamespace", "var", "volatile", "while",
            };
            for (keywords) |keyword| {
                if (eql(name, keyword)) return true;
            }
            return false;
        }
    }.call;

    // Helper function to write a branch name, escaping if it's a Zig keyword
    const writeBranchName = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, name: []const u8) usize {
            var new_pos = p;
            if (isZigKeyword(name)) {
                new_pos = writeStr(buf, new_pos, "@\"");
                new_pos = writeStr(buf, new_pos, name);
                new_pos = writeStr(buf, new_pos, "\"");
            } else {
                new_pos = writeStr(buf, new_pos, name);
            }
            return new_pos;
        }
    }.call;

    // Helper function to reindent text with additional spaces
    const reindentText = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, text: []const u8, additional_indent: []const u8) usize {
            var text_pos = p;
            var i: usize = 0;
            
            while (i < text.len) {
                // Find the end of the current line
                var line_end = i;
                while (line_end < text.len and text[line_end] != '\n') {
                    line_end += 1;
                }
                
                // Write additional indentation if the line is not empty
                if (line_end > i) {
                    // Check if line has content (not just whitespace)
                    var has_content = false;
                    var j = i;
                    while (j < line_end) : (j += 1) {
                        if (text[j] != ' ' and text[j] != '\t') {
                            has_content = true;
                            break;
                        }
                    }
                    
                    if (has_content) {
                        text_pos = writeStr(buf, text_pos, additional_indent);
                    }
                }
                
                // Write the line content
                if (line_end > i) {
                    @memcpy(buf[text_pos..text_pos + (line_end - i)], text[i..line_end]);
                    text_pos += line_end - i;
                }
                
                // Write the newline if present
                if (line_end < text.len) {
                    buf[text_pos] = '\n';
                    text_pos += 1;
                }
                
                i = line_end + 1;
            }
            
            return text_pos;
        }
    }.call;

    // Helper function to find which module an event is defined in
    // Returns the module logical_name, or null if event is in main module
    const findEventModule = struct {
        fn call(event_path: []const []const u8, items: []const Item) ?[]const u8 {
            // Search in submodules first
            for (items) |item| {
                if (item == .module_decl) {
                    const module = item.module_decl;
                    // Check if event is in this module
                    for (module.items) |module_item| {
                        if (module_item == .event_decl) {
                            const event = module_item.event_decl;
                            // Compare paths
                            if (event.path.segments.len == event_path.len) {
                                var matches = true;
                                for (event.path.segments, 0..) |segment, i| {
                                    if (!eql(segment, event_path[i])) {
                                        matches = false;
                                        break;
                                    }
                                }
                                if (matches) {
                                    return module.logical_name;
                                }
                            }
                        }
                    }
                    // Recursively search nested modules
                    if (call(event_path, module.items)) |found| {
                        return found;
                    }
                }
            }
            return null;
        }
    }.call;

    // Helper function to collect all event taps recursively (including from imported modules)
    const collectAllTaps = struct {
        fn call(items: []const Item, taps_buf: *[128]EventTap, count: *usize) void {
            for (items) |item| {
                switch (item) {
                    .event_tap => |tap| {
                        if (count.* < 128) {
                            taps_buf[count.*] = tap;
                            count.* += 1;
                        }
                    },
                    .module_decl => |module| {
                        call(module.items, taps_buf, count);
                    },
                    else => {},
                }
            }
        }
    }.call;

    // Helper function to generate continuation body recursively
    const generateContinuationBody = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, cont: anytype, indent: []const u8, ast_items: anytype, depth: usize, flow_num: usize, flow_pre_label: ?[]const u8, current_label: ?[]const u8) usize {
            var inner_pos = p;
            
            // Process the pipeline steps
            if (cont.pipeline.len > 0) {
                for (cont.pipeline) |step| {
                    switch (step) {
                        .invocation => |inv| {
                            // Generate nested event invocation
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "const nested_result_");
                            var depth_buf: [32]u8 = undefined;
                            const depth_str = std.fmt.bufPrint(&depth_buf, "{}", .{depth}) catch "0";
                            inner_pos = writeStr(buf, inner_pos, depth_str);
                            inner_pos = writeStr(buf, inner_pos, " = ");
                            
                            // Check if event is in a module
                            var event_module: ?[]const u8 = null;
                            for (ast_items) |item| {
                                switch (item) {
                                    .module_decl => |module| {
                                        // Check if invocation path starts with this module's name
                                        // e.g., inv.path = ["io", "print"] and module.logical_name = "io"
                                        if (inv.path.segments.len > 1 and eql(inv.path.segments[0], module.logical_name)) {
                                            // Now check if the event inside the module matches the rest of the path
                                            // e.g., event.path = ["print"] should match inv.path.segments[1..] = ["print"]
                                            for (module.items) |mod_item| {
                                                switch (mod_item) {
                                                    .event_decl => |event| {
                                                        // The event path should match inv.path EXCLUDING the module name
                                                        if (event.path.segments.len == inv.path.segments.len - 1) {
                                                            var matches = true;
                                                            for (event.path.segments, 0..) |seg, j| {
                                                                if (!eql(seg, inv.path.segments[j + 1])) {
                                                                    matches = false;
                                                                    break;
                                                                }
                                                            }
                                                            if (matches) {
                                                                event_module = module.logical_name;
                                                                break;
                                                            }
                                                        }
                                                    },
                                                    else => {},
                                                }
                                            }
                                            if (event_module != null) break;
                                        }
                                    },
                                    else => {},
                                }
                            }

                            // If we didn't find a module prefix in the path AND the path is a single segment,
                            // check if the event is defined in an imported module
                            if (event_module == null and inv.path.segments.len == 1) {
                                event_module = findEventModule(inv.path.segments, ast_items);
                            }

                            // Write event path
                            if (event_module) |mod| {
                                // Module-qualified event: write module.path.to.event
                                inner_pos = writeStr(buf, inner_pos, mod);
                                inner_pos = writeStr(buf, inner_pos, ".");
                                // Determine how many segments to skip
                                // If path is ["io", "print"] and module is "io", skip first segment
                                // If path is ["emit_transition"] and module is "ccp", use all segments
                                const skip_count: usize = if (inv.path.segments.len > 1 and eql(inv.path.segments[0], mod)) 1 else 0;
                                // Write event name/path within the module
                                for (inv.path.segments[skip_count..], 0..) |seg, i| {
                                    if (i > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                    inner_pos = writeStr(buf, inner_pos, seg);
                                }
                            } else {
                                // Event is in current module - use just the last segment
                                inner_pos = writeStr(buf, inner_pos, inv.path.segments[inv.path.segments.len - 1]);
                            }
                            inner_pos = writeStr(buf, inner_pos, "_event.handler(.{");
                            
                            // Write arguments
                            for (inv.args, 0..) |arg, idx| {
                                if (idx > 0) inner_pos = writeStr(buf, inner_pos, ", ");
                                inner_pos = writeStr(buf, inner_pos, " .");
                                inner_pos = writeStr(buf, inner_pos, arg.name);
                                inner_pos = writeStr(buf, inner_pos, " = ");
                                inner_pos = writeStr(buf, inner_pos, arg.value);
                            }
                            inner_pos = writeStr(buf, inner_pos, " });\n");
                            
                            // Generate switch for nested continuations if any
                            if (cont.nested.len > 0) {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "switch (nested_result_");
                                inner_pos = writeStr(buf, inner_pos, depth_str);
                                inner_pos = writeStr(buf, inner_pos, ") {\n");
                                
                                // Generate nested continuations
                                for (cont.nested) |nested| {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    .");
                                    inner_pos = writeBranchName(buf, inner_pos, nested.branch);
                                    inner_pos = writeStr(buf, inner_pos, " => ");
                                    
                                    if (nested.binding) |binding| {
                                        inner_pos = writeStr(buf, inner_pos, "|");
                                        inner_pos = writeStr(buf, inner_pos, binding);
                                        inner_pos = writeStr(buf, inner_pos, "| {\n");
                                    } else {
                                        inner_pos = writeStr(buf, inner_pos, "{\n");
                                    }

                                    // INJECT TAP CALLS for nested event transitions
                                    // Skip tap injection if we're generating a tap function itself
                                    if (flow_num != TAP_FUNCTION_CONTEXT) {
                                        // Collect all taps (including from imported modules)
                                        var all_taps_nested: [128]EventTap = undefined;
                                        var tap_count_nested: usize = 0;
                                        collectAllTaps(ast_items, &all_taps_nested, &tap_count_nested);

                                        // For each tap that matches: inv.path -> * | nested.branch
                                        var tap_idx: usize = 0;
                                        for (all_taps_nested[0..tap_count_nested]) |tap| {
                                                    // Check if this tap matches current transition
                                                    // Source must match nested event invocation (inv.path)
                                                    var source_matches = false;
                                                    if (tap.source) |src| {
                                                        // Check if this is a namespace wildcard (e.g., "http.*")
                                                        const is_namespace_wildcard = src.segments.len > 0 and eql(src.segments[src.segments.len - 1], "*");

                                                        if (is_namespace_wildcard) {
                                                            // Match if inv.path starts with the namespace prefix
                                                            const prefix_len = src.segments.len - 1; // Exclude the "*"
                                                            if (inv.path.segments.len >= prefix_len) {
                                                                source_matches = true;
                                                                for (src.segments[0..prefix_len], 0..) |segment, idx| {
                                                                    if (!eql(segment, inv.path.segments[idx])) {
                                                                        source_matches = false;
                                                                        break;
                                                                    }
                                                                }
                                                            }
                                                        } else {
                                                            // Exact match required
                                                            if (src.segments.len == inv.path.segments.len) {
                                                                source_matches = true;
                                                                for (src.segments, 0..) |segment, idx| {
                                                                    if (!eql(segment, inv.path.segments[idx])) {
                                                                        source_matches = false;
                                                                        break;
                                                                    }
                                                                }
                                                            }
                                                        }
                                                    } else {
                                                        // null source = wildcard (*)
                                                        source_matches = true;
                                                    }

                                                    // Check if tap has continuation for this branch
                                                    var has_branch = false;
                                                    if (source_matches) {
                                                        for (tap.continuations) |tap_cont| {
                                                            // "Transition" branch always acts as wildcard (matches any branch)
                                                            const is_transition_branch = eql(tap_cont.branch, "Transition");
                                                            if (eql(tap_cont.branch, nested.branch) or is_transition_branch) {
                                                                has_branch = true;
                                                                break;
                                                            }
                                                        }
                                                    }

                                                    // If matches, inject tap call
                                                    if (has_branch) {
                                                        // Check what parameter type tap needs
                                                        var tap_needs_transition = false;
                                                        var tap_needs_branch_payload = false;
                                                        for (tap.continuations) |tap_cont| {
                                                            // "Transition" branch always acts as wildcard (matches any branch)
                                                            const is_transition_branch = eql(tap_cont.branch, "Transition");
                                                            if (eql(tap_cont.branch, nested.branch) or is_transition_branch) {
                                                                // Transition meta-type: any source + "Transition" branch
                                                                if (eql(tap_cont.branch, "Transition")) {
                                                                    tap_needs_transition = true;
                                                                    break;
                                                                } else if (tap_cont.binding) |_| {
                                                                    tap_needs_branch_payload = true;
                                                                    break;
                                                                }
                                                            }
                                                        }

                                                        inner_pos = writeStr(buf, inner_pos, indent);
                                                        inner_pos = writeStr(buf, inner_pos, "        __tap");
                                                        var tap_idx_buf: [32]u8 = undefined;
                                                        const tap_idx_str = std.fmt.bufPrint(&tap_idx_buf, "{}", .{tap_idx}) catch "ERROR";
                                                        inner_pos = writeStr(buf, inner_pos, tap_idx_str);
                                                        inner_pos = writeStr(buf, inner_pos, "(");

                                                        // Pass appropriate parameter based on tap binding type
                                                        if (tap_needs_transition) {
                                                            inner_pos = writeStr(buf, inner_pos, ".{ .source = \"");
                                                            // Write source event name (from inv.path)
                                                            for (inv.path.segments, 0..) |seg, seg_idx| {
                                                                if (seg_idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                                                inner_pos = writeStr(buf, inner_pos, seg);
                                                            }
                                                            inner_pos = writeStr(buf, inner_pos, "\", .branch = \"");
                                                            inner_pos = writeStr(buf, inner_pos, nested.branch);
                                                            inner_pos = writeStr(buf, inner_pos, "\", .destination = ");

                                                            // Determine destination from nested continuation pipeline
                                                            var has_destination = false;
                                                            if (nested.pipeline.len > 0) {
                                                                switch (nested.pipeline[0]) {
                                                                    .invocation => |next_inv| {
                                                                        // Check if it's not terminal (_)
                                                                        if (next_inv.path.segments.len > 0 and !eql(next_inv.path.segments[0], "_")) {
                                                                            has_destination = true;
                                                                            inner_pos = writeStr(buf, inner_pos, "\"");
                                                                            for (next_inv.path.segments, 0..) |seg, seg_idx| {
                                                                                if (seg_idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                                                                inner_pos = writeStr(buf, inner_pos, seg);
                                                                            }
                                                                            inner_pos = writeStr(buf, inner_pos, "\"");
                                                                        }
                                                                    },
                                                                    else => {},
                                                                }
                                                            }
                                                            if (!has_destination) {
                                                                inner_pos = writeStr(buf, inner_pos, "null");
                                                            }
                                                            inner_pos = writeStr(buf, inner_pos, ", .duration_ns = null }");
                                                        } else if (tap_needs_branch_payload) {
                                                            // Pass the branch payload binding from the nested continuation
                                                            if (nested.binding) |binding| {
                                                                inner_pos = writeStr(buf, inner_pos, binding);
                                                            }
                                                        }

                                                        inner_pos = writeStr(buf, inner_pos, ");\n");
                                                    }

                                                    tap_idx += 1;
                                        }
                                    } // End of tap injection if statement

                                    // Recursively generate nested body with increased indent
                                    var deeper_indent_buf: [64]u8 = undefined;
                                    var deeper_indent_len: usize = 0;
                                    @memcpy(deeper_indent_buf[0..indent.len], indent);
                                    deeper_indent_len = indent.len;
                                    const extra = "        ";
                                    @memcpy(deeper_indent_buf[deeper_indent_len..deeper_indent_len + extra.len], extra);
                                    deeper_indent_len += extra.len;
                                    const deeper_indent = deeper_indent_buf[0..deeper_indent_len];

                                    inner_pos = call(buf, inner_pos, nested, deeper_indent, ast_items, depth + 1, flow_num, flow_pre_label, null);
                                    
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    },\n");
                                }
                                
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "}\n");
                            } else {
                                // No nested continuations, just consume the result
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = nested_result_");
                                inner_pos = writeStr(buf, inner_pos, depth_str);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                        },
                        .terminal => {
                            // Terminal step - suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }

                            // If we're inside a label loop (flow-level or continuation-level), break it
                            if (current_label) |label| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "break :");
                                inner_pos = writeStr(buf, inner_pos, label);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            } else if (depth == 0 and flow_pre_label != null) {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "break :");
                                inner_pos = writeStr(buf, inner_pos, flow_pre_label.?);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            } else {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "// Terminal\n");
                            }
                        },
                        .label_with_invocation => |label_inv| {
                            // Suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }

                            // Check if this is a declaration (#label) or jump (@label)
                            if (label_inv.is_declaration) {
                                // Assign initial values to state variables BEFORE the loop
                                for (label_inv.invocation.args) |arg| {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                    inner_pos = writeStr(buf, inner_pos, "_");
                                    inner_pos = writeStr(buf, inner_pos, arg.name);
                                    inner_pos = writeStr(buf, inner_pos, " = ");
                                    inner_pos = writeStr(buf, inner_pos, arg.value);
                                    inner_pos = writeStr(buf, inner_pos, ";\n");
                                }

                                // Label declaration - generate while(true) loop
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                inner_pos = writeStr(buf, inner_pos, ": while (true) {\n");

                                // Call the event with state variables (unique result name to avoid shadowing)
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "    const ");
                                inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                inner_pos = writeStr(buf, inner_pos, "_result = ");

                                // Event path - check if it's in a module
                                var label_event_module: ?[]const u8 = null;
                                for (ast_items) |item| {
                                    switch (item) {
                                        .module_decl => |module| {
                                            for (module.items) |mod_item| {
                                                switch (mod_item) {
                                                    .event_decl => |event| {
                                                        if (event.path.segments.len == label_inv.invocation.path.segments.len) {
                                                            var matches = true;
                                                            for (event.path.segments, 0..) |seg, j| {
                                                                if (!eql(seg, label_inv.invocation.path.segments[j])) {
                                                                    matches = false;
                                                                    break;
                                                                }
                                                            }
                                                            if (matches) {
                                                                label_event_module = module.logical_name;
                                                                break;
                                                            }
                                                        }
                                                    },
                                                    else => {},
                                                }
                                            }
                                            if (label_event_module != null) break;
                                        },
                                        else => {},
                                    }
                                }

                                if (label_event_module) |mod| {
                                    inner_pos = writeStr(buf, inner_pos, mod);
                                    inner_pos = writeStr(buf, inner_pos, "_");
                                    // Write just the last segment after module
                                    inner_pos = writeStr(buf, inner_pos, label_inv.invocation.path.segments[label_inv.invocation.path.segments.len - 1]);
                                } else {
                                    // Event is in current module - use just the last segment
                                    inner_pos = writeStr(buf, inner_pos, label_inv.invocation.path.segments[label_inv.invocation.path.segments.len - 1]);
                                }
                                inner_pos = writeStr(buf, inner_pos, "_event.handler(.{");

                                // Pass state variables as arguments
                                for (label_inv.invocation.args, 0..) |arg, idx| {
                                    if (idx > 0) inner_pos = writeStr(buf, inner_pos, ", ");
                                    inner_pos = writeStr(buf, inner_pos, " .");
                                    inner_pos = writeStr(buf, inner_pos, arg.name);
                                    inner_pos = writeStr(buf, inner_pos, " = ");
                                    inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                    inner_pos = writeStr(buf, inner_pos, "_");
                                    inner_pos = writeStr(buf, inner_pos, arg.name);
                                }
                                inner_pos = writeStr(buf, inner_pos, " });\n");

                                // Generate switch over nested continuations
                                if (cont.nested.len > 0) {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    switch (");
                                    inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                    inner_pos = writeStr(buf, inner_pos, "_result) {\n");

                                    for (cont.nested) |nested| {
                                        inner_pos = writeStr(buf, inner_pos, indent);
                                        inner_pos = writeStr(buf, inner_pos, "        .");
                                        inner_pos = writeBranchName(buf, inner_pos, nested.branch);
                                        inner_pos = writeStr(buf, inner_pos, " => ");

                                        // Check if any taps need the branch payload for this transition
                                        var need_synthetic_binding = false;
                                        const synthetic_binding_name: []const u8 = "__tap_payload";

                                        if (flow_num != TAP_FUNCTION_CONTEXT and nested.binding == null) {
                                            // Check if taps need payload
                                            for (ast_items) |tap_check_item| {
                                                if (tap_check_item == .event_tap) {
                                                    const tap_check = tap_check_item.event_tap;
                                                    var src_match = false;
                                                    if (tap_check.source) |src| {
                                                        if (src.segments.len == label_inv.invocation.path.segments.len) {
                                                            src_match = true;
                                                            for (src.segments, 0..) |seg, idx| {
                                                                if (!eql(seg, label_inv.invocation.path.segments[idx])) {
                                                                    src_match = false;
                                                                    break;
                                                                }
                                                            }
                                                        }
                                                    } else {
                                                        src_match = true;
                                                    }
                                                    if (src_match) {
                                                        for (tap_check.continuations) |tap_cont_check| {
                                                            if (eql(tap_cont_check.branch, nested.branch) and tap_cont_check.binding != null) {
                                                                need_synthetic_binding = true;
                                                                break;
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }

                                        // Emit binding - use user's binding, or synthetic if needed
                                        const actual_binding: ?[]const u8 = if (nested.binding) |nb| nb else if (need_synthetic_binding) synthetic_binding_name else null;

                                        if (actual_binding) |nbinding| {
                                            inner_pos = writeStr(buf, inner_pos, "|");
                                            inner_pos = writeStr(buf, inner_pos, nbinding);
                                            inner_pos = writeStr(buf, inner_pos, "| {\n");
                                        } else {
                                            inner_pos = writeStr(buf, inner_pos, "{\n");
                                        }

                                        // INJECT TAP CALLS for label loop transitions
                                        // Skip tap injection if we're generating a tap function itself
                                        if (flow_num != TAP_FUNCTION_CONTEXT) {
                                            // Collect all taps (including from imported modules)
                                            var all_taps: [128]EventTap = undefined;
                                            var tap_count: usize = 0;
                                            collectAllTaps(ast_items, &all_taps, &tap_count);

                                            // For each tap that matches: label_inv.invocation.path -> * | nested.branch
                                            var label_tap_idx: usize = 0;
                                            for (all_taps[0..tap_count]) |tap| {
                                                        // Check if this tap matches current transition
                                                        // Source must match label event invocation
                                                        var source_matches = false;
                                                        if (tap.source) |src| {
                                                            if (src.segments.len == label_inv.invocation.path.segments.len) {
                                                                source_matches = true;
                                                                for (src.segments, 0..) |segment, idx| {
                                                                    if (!eql(segment, label_inv.invocation.path.segments[idx])) {
                                                                        source_matches = false;
                                                                        break;
                                                                    }
                                                                }
                                                            }
                                                        } else {
                                                            // null source = wildcard (*)
                                                            source_matches = true;
                                                        }

                                                        // Check if tap has continuation for this branch
                                                        var has_branch = false;
                                                        if (source_matches) {
                                                            for (tap.continuations) |tap_cont| {
                                                                if (eql(tap_cont.branch, nested.branch)) {
                                                                    has_branch = true;
                                                                    break;
                                                                }
                                                            }
                                                        }

                                                        // If matches, inject tap call
                                                        if (has_branch) {
                                                            // Check what parameter type tap needs and get when clause
                                                            var tap_needs_branch_payload = false;
                                                            var label_tap_when_clause: ?[]const u8 = null;
                                                            var label_tap_binding_name: ?[]const u8 = null;
                                                            for (tap.continuations) |tap_cont| {
                                                                if (eql(tap_cont.branch, nested.branch)) {
                                                                    if (tap_cont.binding) |_| {
                                                                        tap_needs_branch_payload = true;
                                                                    }
                                                                    label_tap_when_clause = tap_cont.condition;
                                                                    label_tap_binding_name = tap_cont.binding;
                                                                    break;
                                                                }
                                                            }

                                                            // Emit when clause check if present
                                                            if (label_tap_when_clause) |when_cond| {
                                                                inner_pos = writeStr(buf, inner_pos, indent);
                                                                inner_pos = writeStr(buf, inner_pos, "            if (");
                                                                // Substitute tap's binding with actual binding at call site
                                                                if (label_tap_binding_name) |tap_binding| {
                                                                    // Replace tap_binding with actual_binding in when_cond
                                                                    var cond_pos: usize = 0;
                                                                    while (cond_pos < when_cond.len) {
                                                                        // Check if we're at the start of the binding name
                                                                        if (cond_pos + tap_binding.len <= when_cond.len) {
                                                                            var matches = true;
                                                                            for (tap_binding, 0..) |ch, idx| {
                                                                                if (when_cond[cond_pos + idx] != ch) {
                                                                                    matches = false;
                                                                                    break;
                                                                                }
                                                                            }

                                                                            // Check it's a word boundary
                                                                            if (matches) {
                                                                                const after = if (cond_pos + tap_binding.len < when_cond.len) when_cond[cond_pos + tap_binding.len] else 0;
                                                                                const before = if (cond_pos > 0) when_cond[cond_pos - 1] else 0;
                                                                                const is_word_char_after = (after >= 'a' and after <= 'z') or (after >= 'A' and after <= 'Z') or (after >= '0' and after <= '9') or after == '_';
                                                                                const is_word_char_before = (before >= 'a' and before <= 'z') or (before >= 'A' and before <= 'Z') or (before >= '0' and before <= '9') or before == '_';

                                                                                if (!is_word_char_before and !is_word_char_after) {
                                                                                    // Replace binding name with actual_binding
                                                                                    if (actual_binding) |ab| {
                                                                                        inner_pos = writeStr(buf, inner_pos, ab);
                                                                                    }
                                                                                    cond_pos += tap_binding.len;
                                                                                    continue;
                                                                                }
                                                                            }
                                                                        }
                                                                        // Copy character as-is
                                                                        buf[inner_pos] = when_cond[cond_pos];
                                                                        inner_pos += 1;
                                                                        cond_pos += 1;
                                                                    }
                                                                } else {
                                                                    inner_pos = writeStr(buf, inner_pos, when_cond);
                                                                }
                                                                inner_pos = writeStr(buf, inner_pos, ") {\n");
                                                                inner_pos = writeStr(buf, inner_pos, indent);
                                                                inner_pos = writeStr(buf, inner_pos, "                __tap");
                                                            } else {
                                                                inner_pos = writeStr(buf, inner_pos, indent);
                                                                inner_pos = writeStr(buf, inner_pos, "            __tap");
                                                            }
                                                            var tap_idx_buf: [32]u8 = undefined;
                                                            const tap_idx_str = std.fmt.bufPrint(&tap_idx_buf, "{}", .{label_tap_idx}) catch "ERROR";
                                                            inner_pos = writeStr(buf, inner_pos, tap_idx_str);
                                                            inner_pos = writeStr(buf, inner_pos, "(");

                                                            // Pass branch payload if tap needs it
                                                            if (tap_needs_branch_payload) {
                                                                if (actual_binding) |nbinding| {
                                                                    inner_pos = writeStr(buf, inner_pos, nbinding);
                                                                }
                                                            }

                                                            inner_pos = writeStr(buf, inner_pos, ");\n");

                                                            // Close when clause if present
                                                            if (label_tap_when_clause) |_| {
                                                                inner_pos = writeStr(buf, inner_pos, indent);
                                                                inner_pos = writeStr(buf, inner_pos, "            }\n");
                                                            }
                                                        }

                                                        label_tap_idx += 1;
                                            }
                                        }

                                        // Recursively generate nested continuation body
                                        const deeper_indent_buf: [64]u8 = undefined;
                                        var deeper_indent: []const u8 = indent;
                                        if (indent.len < 60) {
                                            var di = deeper_indent_buf;
                                            @memcpy(di[0..indent.len], indent);
                                            @memcpy(di[indent.len..indent.len+12], "            ");
                                            deeper_indent = di[0..indent.len+12];
                                        }
                                        inner_pos = call(buf, inner_pos, nested, deeper_indent, ast_items, depth + 1, flow_num, flow_pre_label, label_inv.label);

                                        inner_pos = writeStr(buf, inner_pos, indent);
                                        inner_pos = writeStr(buf, inner_pos, "        },\n");
                                    }

                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    }\n");
                                }

                                // Close the while loop
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "}\n");
                            } else {
                                // Label jump - assign state variables and continue
                                for (label_inv.invocation.args) |arg| {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                    inner_pos = writeStr(buf, inner_pos, "_");
                                    inner_pos = writeStr(buf, inner_pos, arg.name);
                                    inner_pos = writeStr(buf, inner_pos, " = ");
                                    inner_pos = writeStr(buf, inner_pos, arg.value);
                                    inner_pos = writeStr(buf, inner_pos, ";\n");
                                }
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "continue :");
                                inner_pos = writeStr(buf, inner_pos, label_inv.label);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                        },
                        .label_jump => |lj| {
                            // New style label jump: @label(args)
                            // Suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }

                            // Assign state variables and continue
                            for (lj.args) |arg| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, lj.label);
                                inner_pos = writeStr(buf, inner_pos, "_");
                                inner_pos = writeStr(buf, inner_pos, arg.name);
                                inner_pos = writeStr(buf, inner_pos, " = ");
                                inner_pos = writeStr(buf, inner_pos, arg.value);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "continue :");
                            inner_pos = writeStr(buf, inner_pos, lj.label);
                            inner_pos = writeStr(buf, inner_pos, ";\n");
                        },
                        else => {
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "// TODO: Handle other step types\n");
                        },
                    }
                }
            } else {
                // Empty pipeline
                inner_pos = writeStr(buf, inner_pos, indent);
                inner_pos = writeStr(buf, inner_pos, "// Empty continuation\n");
            }
            
            return inner_pos;
        }
    }.call;

    // Generate header using emitter library
    var emit_buffer: [8192]u8 = undefined; // Increased to 8KB for longer host lines
    var emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
    emitter_lib.emitFileHeader(&emitter) catch unreachable;
    @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
    pos += emitter.pos;
    
    // Check if there's a user-defined main function or any flows/events
    var has_user_main = false;
    var has_flows = false;
    var has_events = false;
    
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .host_line => |line| {
                // Simple check: if line starts with "pub fn main"
                if (line.content.len >= 11 and eql(line.content[0..11], "pub fn main")) {
                    has_user_main = true;
                }
            },
            .flow => {
                has_flows = true;
            },
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.segments.len == 0 or !eql(event.path.segments[0], "compiler")) {
                    has_events = true;
                }
            },
            else => {},
        }
    }
    
    // If user defined main and no Koru features, just output as-is
    if (has_user_main and !has_flows and !has_events) {
        // Just output zig_lines directly without module struct (using emitter library)
        for (__koru_event_input.ast.items) |item| {
            switch (item) {
                .host_line => |line| {
                    emitter_lib.emitHostLine(&emitter, line.content) catch unreachable;
                },
                else => {},
            }
        }
        // Copy all emitted content to main buffer
        @memcpy(buffer[0..emitter.pos], emit_buffer[0..emitter.pos]);
        pos = emitter.pos;
        // Return early - no need for further processing
        const final_code = buffer[0..pos];
        return .{ .emitted = .{ .code = final_code } };
    }
    
    // First, collect and group modules by parent namespace (for directory imports)
    // We need to generate nested structs: pub const parent = struct { pub const child = struct {...}; };

    // Group modules: track parent names and their children
    var parent_modules: [64][]const u8 = undefined;
    var parent_counts: [64]usize = undefined;
    var num_parents: usize = 0;

    // Also track non-dotted (regular) modules separately
    var regular_modules: [64]usize = undefined;  // indices into __koru_event_input.ast.items
    var num_regular: usize = 0;

    // First pass: categorize all modules
    var module_idx: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .module_decl => |module| {
                // Check if this is a dotted name (directory import submodule)
                var has_dot = false;
                var dot_pos: usize = 0;
                var i: usize = 0;
                while (i < module.logical_name.len) : (i += 1) {
                    if (module.logical_name[i] == '.') {
                        has_dot = true;
                        dot_pos = i;
                        break;
                    }
                }

                if (has_dot) {
                    // Extract parent name
                    const parent = module.logical_name[0..dot_pos];

                    // Check if we already have this parent
                    var found_parent = false;
                    var p: usize = 0;
                    while (p < num_parents) : (p += 1) {
                        if (eql(parent_modules[p], parent)) {
                            parent_counts[p] += 1;
                            found_parent = true;
                            break;
                        }
                    }

                    if (!found_parent) {
                        parent_modules[num_parents] = parent;
                        parent_counts[num_parents] = 1;
                        num_parents += 1;
                    }
                } else {
                    // Regular (non-dotted) module
                    regular_modules[num_regular] = module_idx;
                    num_regular += 1;
                }
            },
            else => {},
        }
        module_idx += 1;
    }

    // Second pass: generate parent modules with their children
    var p: usize = 0;
    while (p < num_parents) : (p += 1) {
        const parent_name = parent_modules[p];

        // Open parent struct
        pos = writeStr(&buffer, pos, "pub const ");
        pos = writeStr(&buffer, pos, parent_name);
        pos = writeStr(&buffer, pos, " = struct {\n");

        // Find and generate all children of this parent
        for (__koru_event_input.ast.items) |item| {
            switch (item) {
                .module_decl => |module| {
                    // Check if this module belongs to this parent
                    var has_dot = false;
                    var dot_pos: usize = 0;
                    var i: usize = 0;
                    while (i < module.logical_name.len) : (i += 1) {
                        if (module.logical_name[i] == '.') {
                            has_dot = true;
                            dot_pos = i;
                            break;
                        }
                    }

                    if (has_dot) {
                        const this_parent = module.logical_name[0..dot_pos];
                        if (eql(this_parent, parent_name)) {
                            const child_name = module.logical_name[dot_pos + 1..];

                            // Generate child module (indented)
                            pos = writeStr(&buffer, pos, "    pub const ");
                            pos = writeStr(&buffer, pos, child_name);
                            pos = writeStr(&buffer, pos, " = struct {\n");

                            // Process all items in the child module (double-indented)
                            for (module.items) |mod_item| {
                                switch (mod_item) {
                                    .host_line => |line| {
                                        pos = writeStr(&buffer, pos, "        ");
                                        pos = writeStr(&buffer, pos, line.content);
                                        pos = writeStr(&buffer, pos, "\n");
                                    },
                                    .event_decl => |event| {
                                        // Skip compiler events
                                        if (event.path.segments.len > 0 and eql(event.path.segments[0], "compiler")) {
                                            continue;
                                        }

                                        // Skip comptime-only events
                                        var is_comptime_only = false;
                                        for (event.input.fields) |field| {
                                            if (field.is_flow_ast or field.is_source) {
                                                is_comptime_only = true;
                                                break;
                                            }
                                            if (eql(field.type, "ProgramAST") or eql(field.type, "SourceFile")) {
                                                is_comptime_only = true;
                                                break;
                                            }
                                        }
                                        if (is_comptime_only) {
                                            continue;
                                        }

                                        // Generate event struct (double-indented for child module)
                                        pos = writeStr(&buffer, pos, "        pub const ");
                                        pos = writeStr(&buffer, pos, event.path.segments[event.path.segments.len - 1]);
                                        pos = writeStr(&buffer, pos, "_event = struct {\n");

                                        // Input struct
                                        pos = writeStr(&buffer, pos, "            pub const Input = struct {\n");
                                        for (event.input.fields) |field| {
                                            pos = writeStr(&buffer, pos, "                ");
                                            pos = writeStr(&buffer, pos, field.name);
                                            pos = writeStr(&buffer, pos, ": ");
                                            if (field.is_file or field.is_embed_file) {
                                                pos = writeStr(&buffer, pos, "[]const u8");
                                            } else {
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                            pos = writeStr(&buffer, pos, ",\n");
                                        }
                                        pos = writeStr(&buffer, pos, "            };\n");

                                        // Output type
                                        if (event.branches.len == 0) {
                                            pos = writeStr(&buffer, pos, "            pub const Output = void;\n");
                                        } else {
                                            pos = writeStr(&buffer, pos, "            pub const Output = union(enum) {\n");
                                            for (event.branches) |branch| {
                                                pos = writeStr(&buffer, pos, "                ");
                                                pos = writeBranchName(&buffer, pos, branch.name);
                                                pos = writeStr(&buffer, pos, ": struct {\n");
                                                for (branch.payload.fields) |field| {
                                                    pos = writeStr(&buffer, pos, "                    ");
                                                    pos = writeStr(&buffer, pos, field.name);
                                                    pos = writeStr(&buffer, pos, ": ");
                                                    pos = writeStr(&buffer, pos, field.type);
                                                    pos = writeStr(&buffer, pos, ",\n");
                                                }
                                                pos = writeStr(&buffer, pos, "                },\n");
                                            }
                                            pos = writeStr(&buffer, pos, "            };\n");
                                        }

                                        // Handler function
                                        pos = writeStr(&buffer, pos, "            pub fn handler(__koru_event_input: Input) Output {\n");

                                        // Find implementation in the same module
                                        var found_impl = false;
                                        for (module.items) |impl_item| {
                                            switch (impl_item) {
                                                .proc_decl => |proc| {
                                                    if (proc.path.segments.len == event.path.segments.len) {
                                                        var matches = true;
                                                        for (proc.path.segments, 0..) |seg, j| {
                                                            if (!eql(seg, event.path.segments[j])) {
                                                                matches = false;
                                                                break;
                                                            }
                                                        }
                                                        if (matches) {
                                                            if (proc.target) |target| {
                                                                if (!eql(target, "zig")) {
                                                                    continue;
                                                                }
                                                            }

                                                            // Generate implicit input bindings - destructure all input fields
                                                            // This makes procs consistent with subflows by providing direct access to input fields
                                                            for (event.input.fields) |field| {
                                                                pos = writeStr(&buffer, pos, "                const ");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, " = __koru_event_input.");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, ";\n");
                                                            }
                                                            // Suppress unused variable warnings for all destructured fields
                                                            for (event.input.fields) |field| {
                                                                pos = writeStr(&buffer, pos, "                _ = &");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, ";\n");
                                                            }

                                                            // Keep _ = &__koru_event_input for backwards compatibility
                                                            pos = writeStr(&buffer, pos, "                _ = &__koru_event_input;\n");
                                                            pos = reindentText(&buffer, pos, proc.body, "            ");
                                                            pos = writeStr(&buffer, pos, "\n");
                                                            found_impl = true;
                                                            break;
                                                        }
                                                    }
                                                },
                                                else => {},
                                            }
                                        }

                                        if (!found_impl) {
                                            if (event.branches.len > 0) {
                                                pos = writeStr(&buffer, pos, "                return .{ .");
                                                pos = writeBranchName(&buffer, pos, event.branches[0].name);
                                                pos = writeStr(&buffer, pos, " = .{} };\n");
                                            } else {
                                                pos = writeStr(&buffer, pos, "                return undefined;\n");
                                            }
                                        }

                                        pos = writeStr(&buffer, pos, "            }\n");
                                        pos = writeStr(&buffer, pos, "        };\n");
                                    },
                                    else => {},
                                }
                            }

                            // Close child module struct
                            pos = writeStr(&buffer, pos, "    };\n");
                        }
                    }
                },
                else => {},
            }
        }

        // Close parent module struct
        pos = writeStr(&buffer, pos, "};\n\n");
    }

    // Third pass: generate regular (non-dotted) modules
    var r: usize = 0;
    while (r < num_regular) : (r += 1) {
        const module_item_idx = regular_modules[r];
        const item = __koru_event_input.ast.items[module_item_idx];

        switch (item) {
            .module_decl => |module| {
                pos = writeStr(&buffer, pos, "pub const ");
                pos = writeStr(&buffer, pos, module.logical_name);
                pos = writeStr(&buffer, pos, " = struct {\n");

                // Process all items in the regular module
                for (module.items) |mod_item| {
                    switch (mod_item) {
                        .host_line => |line| {
                            pos = writeStr(&buffer, pos, "    ");
                            pos = writeStr(&buffer, pos, line.content);
                            pos = writeStr(&buffer, pos, "\n");
                        },
                        .event_decl => |event| {
                            // Skip compiler events
                            if (event.path.segments.len > 0 and eql(event.path.segments[0], "compiler")) {
                                continue;
                            }

                            // Skip comptime-only events
                            var is_comptime_only = false;
                            for (event.input.fields) |field| {
                                if (field.is_flow_ast or field.is_source) {
                                    is_comptime_only = true;
                                    break;
                                }
                                if (eql(field.type, "ProgramAST") or eql(field.type, "SourceFile")) {
                                    is_comptime_only = true;
                                    break;
                                }
                            }
                            if (is_comptime_only) {
                                continue;
                            }

                            // Generate event struct
                            pos = writeStr(&buffer, pos, "    pub const ");
                            pos = writeStr(&buffer, pos, event.path.segments[event.path.segments.len - 1]);
                            pos = writeStr(&buffer, pos, "_event = struct {\n");

                            // Input struct
                            pos = writeStr(&buffer, pos, "        pub const Input = struct {\n");
                            for (event.input.fields) |field| {
                                pos = writeStr(&buffer, pos, "            ");
                                pos = writeStr(&buffer, pos, field.name);
                                pos = writeStr(&buffer, pos, ": ");
                                if (field.is_file or field.is_embed_file) {
                                    pos = writeStr(&buffer, pos, "[]const u8");
                                } else {
                                    pos = writeStr(&buffer, pos, field.type);
                                }
                                pos = writeStr(&buffer, pos, ",\n");
                            }
                            pos = writeStr(&buffer, pos, "        };\n");

                            // Output type
                            if (event.branches.len == 0) {
                                pos = writeStr(&buffer, pos, "        pub const Output = void;\n");
                            } else {
                                pos = writeStr(&buffer, pos, "        pub const Output = union(enum) {\n");
                                for (event.branches) |branch| {
                                    pos = writeStr(&buffer, pos, "            ");
                                    pos = writeBranchName(&buffer, pos, branch.name);
                                    pos = writeStr(&buffer, pos, ": struct {\n");
                                    for (branch.payload.fields) |field| {
                                        pos = writeStr(&buffer, pos, "                ");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ": ");
                                        pos = writeStr(&buffer, pos, field.type);
                                        pos = writeStr(&buffer, pos, ",\n");
                                    }
                                    pos = writeStr(&buffer, pos, "            },\n");
                                }
                                pos = writeStr(&buffer, pos, "        };\n");
                            }

                            // Handler function
                            pos = writeStr(&buffer, pos, "        pub fn handler(__koru_event_input: Input) Output {\n");

                            // Find implementation in the same module
                            var found_impl = false;
                            for (module.items) |impl_item| {
                                switch (impl_item) {
                                    .proc_decl => |proc| {
                                        if (proc.path.segments.len == event.path.segments.len) {
                                            var matches = true;
                                            for (proc.path.segments, 0..) |seg, j| {
                                                if (!eql(seg, event.path.segments[j])) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            if (matches) {
                                                if (proc.target) |target| {
                                                    if (!eql(target, "zig")) {
                                                        continue;
                                                    }
                                                }

                                                // Generate implicit input bindings - destructure all input fields
                                                // This makes procs consistent with subflows by providing direct access to input fields
                                                for (event.input.fields) |field| {
                                                    pos = writeStr(&buffer, pos, "            const ");
                                                    pos = writeStr(&buffer, pos, field.name);
                                                    pos = writeStr(&buffer, pos, " = __koru_event_input.");
                                                    pos = writeStr(&buffer, pos, field.name);
                                                    pos = writeStr(&buffer, pos, ";\n");
                                                }
                                                // Suppress unused variable warnings for all destructured fields
                                                for (event.input.fields) |field| {
                                                    pos = writeStr(&buffer, pos, "            _ = &");
                                                    pos = writeStr(&buffer, pos, field.name);
                                                    pos = writeStr(&buffer, pos, ";\n");
                                                }

                                                // Keep _ = &e for backwards compatibility if proc uses e directly
                                                pos = writeStr(&buffer, pos, "            _ = &__koru_event_input;\n");
                                                pos = reindentText(&buffer, pos, proc.body, "        ");
                                                pos = writeStr(&buffer, pos, "\n");
                                                found_impl = true;
                                                break;
                                            }
                                        }
                                    },
                                    else => {},
                                }
                            }

                            if (!found_impl) {
                                if (event.branches.len > 0) {
                                    pos = writeStr(&buffer, pos, "            return .{ .");
                                    pos = writeBranchName(&buffer, pos, event.branches[0].name);
                                    pos = writeStr(&buffer, pos, " = .{} };\n");
                                } else {
                                    pos = writeStr(&buffer, pos, "            return undefined;\n");
                                }
                            }

                            pos = writeStr(&buffer, pos, "        }\n");
                            pos = writeStr(&buffer, pos, "    };\n");
                        },
                        else => {},
                    }
                }

                // Close the regular module struct
                pos = writeStr(&buffer, pos, "};\n\n");
            },
            else => {},
        }
    }

    // Now generate the main module struct (using emitter library)
    emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
    emitter_lib.emitMainModuleStart(&emitter) catch unreachable;

    // First pass: Collect zig_lines (imports) - inside the module struct!
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .host_line => |line| {
                emitter_lib.emitHostLineWithIndent(&emitter, "    ", line.content) catch unreachable;
            },
            else => {},
        }
    }

    // Copy main_module start + imports to buffer
    @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
    pos += emitter.pos;

    // Collect all annotation combinations from taps that use transition bindings
    // We need to generate a Transition type for each unique annotation set
    var has_base_transition = false;  // Transition with no annotations
    var has_profiling_transition = false;  // Transition_profiling

    // Helper to recursively check for Transition taps
    const checkTransitionTapsRecursive = struct {
        fn call(items: []const Item, has_base: *bool, has_profiling: *bool) void {
            for (items) |item| {
                switch (item) {
                    .event_tap => |tap| {
                        for (tap.continuations) |cont| {
                            // Transition meta-type: any source + "Transition" branch
                            if (eql(cont.branch, "Transition")) {
                                // Check what annotations this tap has
                                if (tap.annotations.len == 0) {
                                    has_base.* = true;
                                } else {
                                    // Check for profiling annotation
                                    for (tap.annotations) |ann| {
                                        if (eql(ann, "profiling")) {
                                            has_profiling.* = true;
                                        }
                                    }
                                }
                            }
                        }
                    },
                    .module_decl => |module| {
                        call(module.items, has_base, has_profiling);
                    },
                    else => {},
                }
            }
        }
    }.call;

    checkTransitionTapsRecursive(__koru_event_input.ast.items, &has_base_transition, &has_profiling_transition);

    // Generate base Transition type if needed
    if (has_base_transition) {
        emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
        emitter_lib.emitTransitionType(&emitter) catch unreachable;
        @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
        pos += emitter.pos;
    }

    // Generate Transition_profiling type if needed
    if (has_profiling_transition) {
        emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
        emitter_lib.emitTransitionProfilingType(&emitter) catch unreachable;
        @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
        pos += emitter.pos;
    }

    // Second pass: Generate inline flow helper functions
    // These are module-level functions that wrap inline flows from procs
    var inline_flow_counter: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .module_decl => continue,
            .proc_decl => |proc| {
                if (proc.inline_flows.len > 0) {
                    // Generate helper function for each inline flow
                    for (proc.inline_flows) |inline_flow| {
                        inline_flow_counter += 1;

                        // Function signature: fn __inline_flow_N(args: ProcEventName.Input) ReturnType
                        // IMPORTANT: Use PROC's event input type, not first invoked event's input!
                        // This allows access to ALL proc parameters, including those used in later pipeline steps.
                        pos = writeStr(&buffer, pos, "    fn __inline_flow_");
                        var counter_buf: [32]u8 = undefined;
                        const counter_str = std.fmt.bufPrint(&counter_buf, "{d}", .{inline_flow_counter}) catch "0";
                        pos = writeStr(&buffer, pos, counter_str);
                        pos = writeStr(&buffer, pos, "(args: ");

                        // Input type from PROC's event (not invoked event)
                        // Find the event that matches this proc's path
                        var proc_event_module: ?[]const u8 = null;
                        var proc_event_input_shape: ?Shape = null;
                        // Events can be at top level OR inside module_decl
                        for (__koru_event_input.ast.items) |ast_item| {
                            switch (ast_item) {
                                .event_decl => |event| {
                                    // Top-level event
                                    if (event.path.segments.len == proc.path.segments.len) {
                                        var matches = true;
                                        for (event.path.segments, 0..) |seg, j| {
                                            if (!eql(seg, proc.path.segments[j])) {
                                                matches = false;
                                                break;
                                            }
                                        }
                                        if (matches) {
                                            proc_event_input_shape = event.input;
                                            break;
                                        }
                                    }
                                },
                                .module_decl => |module| {
                                    // Event inside module
                                    for (module.items) |mod_item| {
                                        switch (mod_item) {
                                            .event_decl => |event| {
                                                if (event.path.segments.len == proc.path.segments.len) {
                                                    var matches = true;
                                                    for (event.path.segments, 0..) |seg, j| {
                                                        if (!eql(seg, proc.path.segments[j])) {
                                                            matches = false;
                                                            break;
                                                        }
                                                    }
                                                    if (matches) {
                                                        proc_event_module = module.logical_name;
                                                        proc_event_input_shape = event.input;
                                                        break;
                                                    }
                                                }
                                            },
                                            else => {},
                                        }
                                    }
                                    if (proc_event_input_shape != null) break;
                                },
                                else => {},
                            }
                        }

                        if (proc_event_module) |mod| {
                            pos = writeStr(&buffer, pos, mod);
                            pos = writeStr(&buffer, pos, ".");
                            pos = writeStr(&buffer, pos, proc.path.segments[proc.path.segments.len - 1]);
                        } else {
                            pos = writeStr(&buffer, pos, proc.path.segments[proc.path.segments.len - 1]);
                        }
                        pos = writeStr(&buffer, pos, "_event.Input) ");

                        // Now also look up the INVOKED event's module (for generating the handler call)
                        var inline_event_module: ?[]const u8 = null;
                        for (__koru_event_input.ast.items) |ast_item| {
                            switch (ast_item) {
                                .module_decl => |module| {
                                    for (module.items) |mod_item| {
                                        switch (mod_item) {
                                            .event_decl => |event| {
                                                if (event.path.segments.len == inline_flow.invocation.path.segments.len) {
                                                    var matches = true;
                                                    for (event.path.segments, 0..) |seg, j| {
                                                        if (!eql(seg, inline_flow.invocation.path.segments[j])) {
                                                            matches = false;
                                                            break;
                                                        }
                                                    }
                                                    if (matches) {
                                                        inline_event_module = module.logical_name;
                                                        break;
                                                    }
                                                }
                                            },
                                            else => {},
                                        }
                                    }
                                    if (inline_event_module != null) break;
                                },
                                else => {},
                            }
                        }

                        // Output type: Determine if this is a terminal flow (directly returned) or assigned
                        // Terminal flows should match proc's Output type, assigned flows use synthetic types
                        // A flow is terminal if it's immediately returned from the proc (matches proc's output type)
                        // Otherwise it's assigned and creates a synthetic type
                        //
                        // Terminal patterns:
                        //   - `return __inline_flow_N(...)` (direct return)
                        //   - `const x = __inline_flow_N(...); return x;` (immediate return of variable)
                        //
                        // Assigned patterns:
                        //   - `const x = __inline_flow_N(...); ... other code ... return .{ .done = .{} };`
                        const terminal_check_str = std.fmt.bufPrint(&counter_buf, "__inline_flow_{d}", .{inline_flow_counter}) catch "0";
                        const contains_flow = std.mem.indexOf(u8, proc.body, terminal_check_str) != null;

                        // Check if flow is directly returned: `return __inline_flow_N(`
                        const direct_return_pattern = std.fmt.bufPrint(&counter_buf, "return __inline_flow_{d}(", .{inline_flow_counter}) catch "0";
                        const is_direct_return = std.mem.indexOf(u8, proc.body, direct_return_pattern) != null;

                        // Check if flow is assigned and immediately returned: `const x = __inline_flow_N(...); return x;`
                        // This is complex to detect perfectly, so we use a simple heuristic:
                        // If the body contains the flow AND "return output" or similar, it's likely terminal
                        const has_return_output = std.mem.indexOf(u8, proc.body, "return output") != null;

                        const is_terminal = contains_flow and (is_direct_return or has_return_output);

                        if (is_terminal) {
                            // Terminal flow - use proc's event Output type
                            for (proc.path.segments, 0..) |seg, idx| {
                                if (idx > 0) pos = writeStr(&buffer, pos, ".");
                                pos = writeStr(&buffer, pos, seg);
                            }
                            pos = writeStr(&buffer, pos, "_event.Output {\n");
                        } else {
                            // Assigned flow - generate synthetic union based on branch constructors
                            pos = writeStr(&buffer, pos, "union(enum) {\n");

                            // Track unique branch names to avoid duplicates
                            var seen_branches: [32][]const u8 = undefined;
                            var seen_count: usize = 0;

                            // Collect unique branch names from continuations
                            for (inline_flow.continuations) |cont| {
                                if (cont.pipeline.len > 0) {
                                    switch (cont.pipeline[0]) {
                                        .branch_constructor => |bc| {
                                            // Check if we've already seen this branch name
                                            var already_seen = false;
                                            for (seen_branches[0..seen_count]) |seen| {
                                                if (eql(seen, bc.branch_name)) {
                                                    already_seen = true;
                                                    break;
                                                }
                                            }
                                            if (already_seen) continue;

                                            // Remember this branch
                                            seen_branches[seen_count] = bc.branch_name;
                                            seen_count += 1;

                                            pos = writeStr(&buffer, pos, "            ");
                                            pos = writeBranchName(&buffer, pos, bc.branch_name);
                                            pos = writeStr(&buffer, pos, ": struct {");

                                            // Write fields - need to look up actual types from event declaration
                                            // Find the event corresponding to this PROC (not the invoked event!)
                                            // The branch constructor creates branches that match the proc's event output
                                            var target_event: ?*const EventDecl = null;
                                            for (__koru_event_input.ast.items) |ast_item| {
                                                switch (ast_item) {
                                                    .event_decl => |*event| {
                                                        if (event.path.segments.len == proc.path.segments.len) {
                                                            var event_matches = true;
                                                            for (event.path.segments, 0..) |seg, seg_idx| {
                                                                if (!eql(seg, proc.path.segments[seg_idx])) {
                                                                    event_matches = false;
                                                                    break;
                                                                }
                                                            }
                                                            if (event_matches) {
                                                                target_event = event;
                                                                break;
                                                            }
                                                        }
                                                    },
                                                    else => {},
                                                }
                                            }

                                            for (bc.fields, 0..) |field, field_idx| {
                                                if (field_idx == 0) {
                                                    pos = writeStr(&buffer, pos, " ");
                                                } else {
                                                    pos = writeStr(&buffer, pos, ", ");
                                                }
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ": ");

                                                // Look up actual field type from event declarations
                                                var field_type: []const u8 = field.type;
                                                if (eql(field.type, "auto")) {
                                                    // Try proc's event first
                                                    if (target_event) |evt| {
                                                        for (evt.branches) |branch| {
                                                            if (eql(branch.name, bc.branch_name)) {
                                                                for (branch.payload.fields) |event_field| {
                                                                    if (eql(event_field.name, field.name)) {
                                                                        field_type = event_field.type;
                                                                        break;
                                                                    }
                                                                }
                                                                break;
                                                            }
                                                        }
                                                    }

                                                    // If still auto, try invoked event
                                                    if (eql(field_type, "auto")) {
                                                        for (__koru_event_input.ast.items) |ast_item| {
                                                            switch (ast_item) {
                                                                .event_decl => |*event| {
                                                                    if (event.path.segments.len == inline_flow.invocation.path.segments.len) {
                                                                        var event_matches = true;
                                                                        for (event.path.segments, 0..) |seg, seg_idx| {
                                                                            if (!eql(seg, inline_flow.invocation.path.segments[seg_idx])) {
                                                                                event_matches = false;
                                                                                break;
                                                                            }
                                                                        }
                                                                        if (event_matches) {
                                                                            // Look in this event's output branches
                                                                            for (event.branches) |branch| {
                                                                                if (eql(branch.name, bc.branch_name)) {
                                                                                    for (branch.payload.fields) |event_field| {
                                                                                        if (eql(event_field.name, field.name)) {
                                                                                            field_type = event_field.type;
                                                                                            break;
                                                                                        }
                                                                                    }
                                                                                    break;
                                                                                }
                                                                            }
                                                                            break;
                                                                        }
                                                                    }
                                                                },
                                                                else => {},
                                                            }
                                                        }
                                                    }
                                                }
                                                pos = writeStr(&buffer, pos, field_type);
                                            }

                                            pos = writeStr(&buffer, pos, " },\n");
                                        },
                                        else => {},
                                    }
                                }
                            }

                            pos = writeStr(&buffer, pos, "        } {\n");
                        }

                        // INLINE FLOW FIX: Destructure args to make proc parameters available
                        // Generate: const field1 = args.field1; const field2 = args.field2; ...
                        // This allows nested invocations to use bare field names (e.g., "c") instead of "args.c"
                        if (proc_event_input_shape) |input_shape| {
                            if (input_shape.fields.len > 0) {
                                for (input_shape.fields) |field| {
                                    pos = writeStr(&buffer, pos, "        const ");
                                    pos = writeStr(&buffer, pos, field.name);
                                    pos = writeStr(&buffer, pos, " = args.");
                                    pos = writeStr(&buffer, pos, field.name);
                                    pos = writeStr(&buffer, pos, ";\n");
                                }
                                // Suppress unused variable warnings
                                for (input_shape.fields) |field| {
                                    pos = writeStr(&buffer, pos, "        _ = &");
                                    pos = writeStr(&buffer, pos, field.name);
                                    pos = writeStr(&buffer, pos, ";\n");
                                }
                            } else {
                                // No fields - suppress unused args parameter
                                pos = writeStr(&buffer, pos, "        _ = &args;\n");
                            }
                        } else {
                            // No input shape - suppress unused args parameter
                            pos = writeStr(&buffer, pos, "        _ = &args;\n");
                        }

                        // Call the invoked event handler (reuse module lookup from above)
                        pos = writeStr(&buffer, pos, "        const result = ");
                        if (inline_event_module) |mod| {
                            pos = writeStr(&buffer, pos, mod);
                            pos = writeStr(&buffer, pos, "_");
                            // Write just the last segment after module
                            pos = writeStr(&buffer, pos, inline_flow.invocation.path.segments[inline_flow.invocation.path.segments.len - 1]);
                        } else {
                            // Event is in current module - use just the last segment
                            pos = writeStr(&buffer, pos, inline_flow.invocation.path.segments[inline_flow.invocation.path.segments.len - 1]);
                        }
                        pos = writeStr(&buffer, pos, "_event.handler(.{ ");

                        // Map arguments using the invocation's argument mapping
                        for (inline_flow.invocation.args, 0..) |arg, arg_idx| {
                            if (arg_idx > 0) pos = writeStr(&buffer, pos, ", ");
                            pos = writeStr(&buffer, pos, ".");
                            pos = writeStr(&buffer, pos, arg.name);
                            pos = writeStr(&buffer, pos, " = ");

                            // Check if arg.value is a field reference or a literal/expression
                            // Field references start with letter/underscore, literals don't
                            const first_char = arg.value[0];
                            const is_field_ref = (first_char >= 'a' and first_char <= 'z') or
                                                  (first_char >= 'A' and first_char <= 'Z') or
                                                  first_char == '_';

                            if (is_field_ref) {
                                pos = writeStr(&buffer, pos, "args.");
                            }
                            pos = writeStr(&buffer, pos, arg.value);
                        }

                        pos = writeStr(&buffer, pos, " });\n");

                        // Generate switch statement to map branches to constructors
                        pos = writeStr(&buffer, pos, "        return switch (result) {\n");

                        for (inline_flow.continuations) |cont| {
                            pos = writeStr(&buffer, pos, "            .");
                            pos = writeBranchName(&buffer, pos, cont.branch);
                            pos = writeStr(&buffer, pos, " => ");

                            // Check if binding is actually used in any expression
                            var binding_used = false;
                            if (cont.binding) |binding| {
                                if (cont.pipeline.len > 0) {
                                    switch (cont.pipeline[0]) {
                                        .branch_constructor => |bc| {
                                            for (bc.fields) |field| {
                                                if (field.expression_str) |expr| {
                                                    if (std.mem.indexOf(u8, expr, binding) != null) {
                                                        binding_used = true;
                                                        break;
                                                    }
                                                }
                                            }
                                        },
                                        else => {},
                                    }
                                }

                                // Only capture binding if it's used
                                if (binding_used) {
                                    pos = writeStr(&buffer, pos, "|");
                                    pos = writeStr(&buffer, pos, binding);
                                    pos = writeStr(&buffer, pos, "| ");
                                }
                            }

                            // Generate branch constructor (always wrapped in union)
                            if (cont.pipeline.len > 0) {
                                switch (cont.pipeline[0]) {
                                    .branch_constructor => |bc| {
                                        pos = writeStr(&buffer, pos, ".{ .");
                                        pos = writeBranchName(&buffer, pos, bc.branch_name);
                                        pos = writeStr(&buffer, pos, " = .{");

                                        for (bc.fields, 0..) |field, idx| {
                                            if (idx > 0) pos = writeStr(&buffer, pos, ", ");
                                            pos = writeStr(&buffer, pos, " .");
                                            pos = writeStr(&buffer, pos, field.name);
                                            pos = writeStr(&buffer, pos, " = ");

                                            // Use expression_str if available, otherwise type
                                            if (field.expression_str) |expr| {
                                                pos = writeStr(&buffer, pos, expr);
                                            } else {
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                        }

                                        pos = writeStr(&buffer, pos, " } }");
                                    },
                                    .invocation => |inv| {
                                        // Pipeline contains an invocation - need to call it and handle nested continuations
                                        // Generate: { const nested_result = event.handler(...); switch (nested_result) { ... nested ... } }
                                        // First, capture the binding if it's used in the invocation args
                                        var parent_binding_needed = false;
                                        if (cont.binding) |binding| {
                                            for (inv.args) |arg| {
                                                if (std.mem.indexOf(u8, arg.value, binding) != null) {
                                                    parent_binding_needed = true;
                                                    break;
                                                }
                                            }
                                        }

                                        if (parent_binding_needed and cont.binding != null) {
                                            pos = writeStr(&buffer, pos, "|");
                                            pos = writeStr(&buffer, pos, cont.binding.?);
                                            pos = writeStr(&buffer, pos, "| ");
                                        }

                                        pos = writeStr(&buffer, pos, "{\n");
                                        pos = writeStr(&buffer, pos, "                const nested_result = ");

                                        // Write event name
                                        pos = writeStr(&buffer, pos, inv.path.segments[inv.path.segments.len - 1]);
                                        pos = writeStr(&buffer, pos, "_event.handler(.{");

                                        // Write arguments
                                        for (inv.args, 0..) |arg, arg_idx| {
                                            if (arg_idx > 0) pos = writeStr(&buffer, pos, ", ");
                                            pos = writeStr(&buffer, pos, " .");
                                            pos = writeStr(&buffer, pos, arg.name);
                                            pos = writeStr(&buffer, pos, " = ");
                                            pos = writeStr(&buffer, pos, arg.value);
                                        }
                                        pos = writeStr(&buffer, pos, " });\n");

                                        // Generate nested switch if there are nested continuations
                                        if (cont.nested.len > 0) {
                                            pos = writeStr(&buffer, pos, "                return switch (nested_result) {\n");

                                            for (cont.nested) |nested| {
                                                pos = writeStr(&buffer, pos, "                    .");
                                                pos = writeBranchName(&buffer, pos, nested.branch);
                                                pos = writeStr(&buffer, pos, " => ");

                                                // Capture binding if present and used
                                                if (nested.binding) |binding| {
                                                    var nested_binding_used = false;
                                                    if (nested.pipeline.len > 0) {
                                                        switch (nested.pipeline[0]) {
                                                            .branch_constructor => |nested_bc| {
                                                                for (nested_bc.fields) |field| {
                                                                    if (field.expression_str) |expr| {
                                                                        if (std.mem.indexOf(u8, expr, binding) != null) {
                                                                            nested_binding_used = true;
                                                                            break;
                                                                        }
                                                                    }
                                                                }
                                                            },
                                                            else => {},
                                                        }
                                                    }
                                                    if (nested_binding_used) {
                                                        pos = writeStr(&buffer, pos, "|");
                                                        pos = writeStr(&buffer, pos, binding);
                                                        pos = writeStr(&buffer, pos, "| ");
                                                    }
                                                }

                                                // Generate nested branch constructor
                                                if (nested.pipeline.len > 0) {
                                                    switch (nested.pipeline[0]) {
                                                        .branch_constructor => |nested_bc| {
                                                            pos = writeStr(&buffer, pos, ".{ .");
                                                            pos = writeBranchName(&buffer, pos, nested_bc.branch_name);
                                                            pos = writeStr(&buffer, pos, " = .{");

                                                            for (nested_bc.fields, 0..) |field, idx| {
                                                                if (idx > 0) pos = writeStr(&buffer, pos, ", ");
                                                                pos = writeStr(&buffer, pos, " .");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, " = ");

                                                                // Use expression_str if available, otherwise type
                                                                if (field.expression_str) |expr| {
                                                                    pos = writeStr(&buffer, pos, expr);
                                                                } else {
                                                                    pos = writeStr(&buffer, pos, field.type);
                                                                }
                                                            }

                                                            pos = writeStr(&buffer, pos, " } }");
                                                        },
                                                        else => {},
                                                    }
                                                }

                                                pos = writeStr(&buffer, pos, ",\n");
                                            }

                                            pos = writeStr(&buffer, pos, "                };\n");
                                        }

                                        pos = writeStr(&buffer, pos, "            }");
                                    },
                                    else => {},
                                }
                            } else {
                                // Empty pipeline (discard case): generate empty block
                                pos = writeStr(&buffer, pos, "{}");
                            }

                            pos = writeStr(&buffer, pos, ",\n");
                        }

                        pos = writeStr(&buffer, pos, "        };\n");
                        pos = writeStr(&buffer, pos, "    }\n");
                    }
                }
            },
            else => {},
        }
    }

    // Second pass: Generate host type declarations (using emitter library)
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .module_decl => continue,
            .host_type_decl => |host_type| {
                emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
                emitter_lib.emitHostTypeDeclInMainModule(&emitter, &host_type) catch unreachable;
                @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
                pos += emitter.pos;
            },
            else => {},
        }
    }

    // Third pass: Generate events (only local ones, not imported) - using emitter library
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.segments.len > 0 and eql(event.path.segments[0], "compiler")) {
                    continue;
                }

                // Skip comptime-only events (with FlowAST, ProgramAST, or Source parameters)
                var is_comptime_only = false;
                for (event.input.fields) |field| {
                    if (field.is_flow_ast or field.is_source) {
                        is_comptime_only = true;
                        break;
                    }
                    if (eql(field.type, "ProgramAST") or eql(field.type, "SourceFile")) {
                        is_comptime_only = true;
                        break;
                    }
                }
                if (is_comptime_only) {
                    continue;
                }

                // Generate event using emitter library
                emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
                emitter_lib.emitEventDeclInMainModule(&emitter, &event, __koru_event_input.ast.items) catch unreachable;
                @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
                pos += emitter.pos;
            },
            else => {},
        }
    }

    // Generate simple tap registry (placeholder for now) - inside main_module
    emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
    emitter_lib.emitTapRegistryPlaceholder(&emitter) catch unreachable;
    @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
    pos += emitter.pos;

    // Helper to recursively generate tap functions from items and nested modules
    const GenerateTapsContext = struct {
        buffer_ptr: *[MAX_SIZE]u8,
        pos_ptr: *usize,
        counter_ptr: *usize,
        root_items: []const Item,
    };

    const generateTapsRecursive = struct {
        fn call(ctx: GenerateTapsContext, items: []const Item) void {
            for (items) |item| {
                switch (item) {
                    .event_tap => |tap| {
                        // Check if this tap uses transition binding
                        var has_transition_binding = false;
                        var has_branch_binding = false;
                        if (tap.continuations.len > 0) {
                            // Transition meta-type: any source + "Transition" branch
                            if (eql(tap.continuations[0].branch, "Transition")) {
                                has_transition_binding = true;
                            } else if (tap.continuations[0].binding) |_| {
                                has_branch_binding = true;
                            }
                        }

                        // Generate tap function with __tap prefix to avoid name conflicts
                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "    fn __tap");
                        var tap_num_buf: [32]u8 = undefined;
                        const tap_num_str = std.fmt.bufPrint(&tap_num_buf, "{}", .{ctx.counter_ptr.*}) catch "ERROR";
                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, tap_num_str);
                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "(");

                        // Add parameter based on binding type
                        if (has_transition_binding) {
                            if (tap.continuations[0].binding) |binding| {
                                ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, binding);
                                ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, ": ");

                                // Determine type name based on annotations
                                if (tap.annotations.len == 0) {
                                    ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "Transition");
                                } else {
                                    // Check for profiling annotation
                                    var has_profiling = false;
                                    for (tap.annotations) |ann| {
                                        if (eql(ann, "profiling")) {
                                            has_profiling = true;
                                        }
                                    }
                                    if (has_profiling) {
                                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "Transition_profiling");
                                    } else {
                                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "Transition");
                                    }
                                }
                            }
                        } else if (has_branch_binding) {
                            // Branch payload binding - use anytype for simplicity
                            if (tap.continuations[0].binding) |binding| {
                                ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, binding);
                                ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, ": anytype");
                            }
                        }

                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, ") void {\n");

                        // Generate tap continuations with proper indentation
                        // NOTE: When clause is NOT included here - it belongs at the call site!
                        if (tap.continuations.len > 0) {
                            ctx.pos_ptr.* = generateContinuationBody(ctx.buffer_ptr, ctx.pos_ptr.*, tap.continuations[0], "        ", ctx.root_items, 0, TAP_FUNCTION_CONTEXT, null, null);
                        }

                        ctx.pos_ptr.* = writeStr(ctx.buffer_ptr, ctx.pos_ptr.*, "    }\n");
                        ctx.counter_ptr.* += 1;
                    },
                    .module_decl => |module| {
                        call(ctx, module.items);
                    },
                    else => {},
                }
            }
        }
    }.call;

    // Generate tap helper functions (one per tap)
    var tap_counter: usize = 0;
    const gen_ctx = GenerateTapsContext{
        .buffer_ptr = &buffer,
        .pos_ptr = &pos,
        .counter_ptr = &tap_counter,
        .root_items = __koru_event_input.ast.items,
    };
    generateTapsRecursive(gen_ctx, __koru_event_input.ast.items);

    // Continue with flows as functions (we're already inside main_module)

    var flow_counter: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .flow => |flow| {
                // Use emitter library for flow generation
                var flow_emit_buffer: [MAX_SIZE]u8 = undefined;
                var flow_emitter = emitter_lib.CodeEmitter.init(&flow_emit_buffer);
                emitter_lib.emitFlowInMainModule(&flow_emitter, &flow, __koru_event_input.ast.items, flow_counter, TAP_FUNCTION_CONTEXT) catch unreachable;
                @memcpy(buffer[pos..pos+flow_emitter.pos], flow_emit_buffer[0..flow_emitter.pos]);
                pos += flow_emitter.pos;

                flow_counter += 1;
            },
            else => {},
        }
    }

    // Close the main_module struct (using emitter library)
    emitter = emitter_lib.CodeEmitter.init(&emit_buffer);
    emitter_lib.emitMainModuleEnd(&emitter) catch unreachable;
    @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
    pos += emitter.pos;

    // Generate minimal main function that calls flows from main_module (using emitter library)
    emitter = emitter_lib.CodeEmitter.init(&emit_buffer); // Reuse emitter
    emitter_lib.emitMainFunctionStart(&emitter) catch unreachable;

    var flow_count: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .flow => {
                emitter_lib.emitFlowCallInMain(&emitter, flow_count) catch unreachable;
                flow_count += 1;
            },
            else => {},
        }
    }

    emitter_lib.emitMainFunctionEnd(&emitter) catch unreachable;

    // Copy main function to final buffer
    @memcpy(buffer[pos..pos+emitter.pos], emit_buffer[0..emitter.pos]);
    pos += emitter.pos;

    // Return the emitted code!
    const final_code = buffer[0..pos];
    return .{ .emitted = .{ .code = final_code } };
    }
};

const compiler_parse = struct {
    pub const Input = struct { source: []const u8, module_name: []const u8 };
    pub const Output = union(enum) { parsed: struct { items: []Item }, failed: struct { message: []const u8 } };
    pub fn handler(__koru_event_input: Input) Output {

    const Parser = @import("parser").Parser;
    // Note: 'std' is already imported at top level by the emitter

    // Use a comptime-friendly allocator
    // Note: In actual comptime context, we'd use a fixed buffer allocator
    // For now, we use the standard allocator which works at comptime
    var buffer: [1024 * 1024]u8 = undefined; // 1MB buffer for parsing
    var fba = std.heap.FixedBufferAllocator.init(&buffer);
    const allocator = fba.allocator();

    // Initialize parser
    var parser = Parser.init(allocator, __koru_event_input.source, __koru_event_input.module_name) catch {
        return .{ .failed = .{ .message = "Failed to initialize parser" } };
    };
    defer parser.deinit();

    // Parse the source
    const parse_result = parser.parse() catch {
        // Try to get error details if available
        if (parser.reporter.hasErrors()) {
            return .{ .failed = .{ .message = "Parse error - see compiler output" } };
        }
        return .{ .failed = .{ .message = "Failed to parse source" } };
    };

    // Return the parsed items
    // Note: The items are allocated in our buffer, which is stack-allocated
    // This is fine for comptime usage where everything gets evaluated away
    return .{ .parsed = .{ .items = parse_result.source_file.items } };
    }
};

const compiler_passes_evaluate_comptime = struct {
    pub const Input = struct { ast: *const SourceFile, allocator: std.mem.Allocator };
    pub const Output = union(enum) { evaluated: struct { ast: *const SourceFile, events_executed: usize } };
    pub fn handler(__koru_event_input: Input) !Output {
        const allocator = __koru_event_input.allocator;

    // Phase 1: Build map of comptime-only events
    // (Events that have FlowAST, ProgramAST, or Source parameters)
    var comptime_events: [64][]const u8 = undefined;
    var comptime_count: usize = 0;

    for (__koru_event_input.ast.items) |item| {
        switch (item) {
            .event_decl => |event_decl| {
                // Check if this event has comptime-only parameters
                var is_comptime = false;
                for (event_decl.input.fields) |field| {
                    if (field.is_flow_ast or field.is_source) {
                        is_comptime = true;
                        break;
                    }
                    if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "SourceFile")) {
                        is_comptime = true;
                        break;
                    }
                }

                if (is_comptime and comptime_count < 64) {
                    // Build event name from path segments
                    const event_name = joinPath(event_decl.path.segments);
                    comptime_events[comptime_count] = event_name;
                    comptime_count += 1;
                }
            },
            .module_decl => |module| {
                // Also check imported modules
                for (module.items) |mod_item| {
                    if (mod_item == .event_decl) {
                        const event_decl = mod_item.event_decl;
                        var is_comptime = false;
                        for (event_decl.input.fields) |field| {
                            if (field.is_flow_ast or field.is_source) {
                                is_comptime = true;
                                break;
                            }
                            if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "SourceFile")) {
                                is_comptime = true;
                                break;
                            }
                        }

                        if (is_comptime and comptime_count < 64) {
                            const event_name = joinPath(event_decl.path.segments);
                            comptime_events[comptime_count] = event_name;
                            comptime_count += 1;
                        }
                    }
                }
            },
            else => {},
        }
    }

    // Phase 2: Walk flows and find comptime event invocations
    // std.debug.print("  Phase 2: Scanning flows for comptime invocations...\n", .{});
    for (__koru_event_input.ast.items) |item| {
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);
            // std.debug.print("    Flow invokes: {s}\n", .{inv_path});

            // Check if this invocation is to a comptime event
            var i: usize = 0;
            while (i < comptime_count) : (i += 1) {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    // Found a comptime event invocation!
                    // std.debug.print("  âś“ Found comptime invocation: {s}\n", .{inv_path});

                    // Call the comptime handler!
                    const handler_result = callComptimeHandler(inv_path, __koru_event_input.ast);

                    // For now, just print that we called it
                    // TODO: Use result to transform flow/AST
                    switch (handler_result) {
                        .none => {
                            // std.debug.print("  WARNING: Handler not found for: {s}\n", .{inv_path});
                        },
                    }

                    break;
                }
            }
        }
    }

    // std.debug.print("  Detected {} comptime events, {} invocations\n", .{comptime_count, invocations_found});

    // Phase 3: Build new AST without comptime flows and [raw] procs (AST TRANSFORMATION!)
    // Count non-comptime items first
    var count_non_comptime: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);

            // Check if comptime flow
            for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path.segments);
                var is_comptime = false;
                for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            count_non_comptime += 1;
        }
    }

    // Build new array with exact size (now allocated at runtime)
    const new_items = try allocator.alloc(Item, count_non_comptime);
    var idx: usize = 0;
    for (__koru_event_input.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path.segments);

            // Check if comptime flow
            for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path.segments);
                var is_comptime = false;
                for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            new_items[idx] = item;
            idx += 1;
        }
    }

    const transformed_ast = try allocator.create(SourceFile);
    transformed_ast.* = SourceFile{
        .items = new_items,
        .allocator = allocator,
    };

    return .{ .evaluated = .{
        .ast = transformed_ast,
        .events_executed = 0  // No longer tracked after debug logging removal
    } };
    }
};

const compiler_passes_inject_ccp = struct {
    pub const Input = struct { ast: *const SourceFile, allocator: std.mem.Allocator };
    pub const Output = union(enum) { instrumented: struct { ast: *const SourceFile } };
    pub fn handler(__koru_event_input: Input) !Output {
        const allocator = __koru_event_input.allocator;

    // Inject CCP observability helpers as self-contained Zig code
    // Uses __ccp_std local import to avoid namespace pollution

    // CCP is a self-governing feature that requires BOTH:
    // 1. User imports $std/ccp (declares intent to use CCP)
    // 2. Compiler flag --ccp is set (enables CCP infrastructure)
    // This pattern allows features to exist in AST but remain dormant without flags

    // Check if --ccp flag is set
    if (!CompilerEnv.hasFlag("ccp")) {
        return .{ .instrumented = .{ .ast = __koru_event_input.ast } };
    }

    // Check if $std/ccp was imported (user declared intent)
    var has_ccp_import = false;
    for (__koru_event_input.ast.items) |item| {
        if (item == .import_decl) {
            const imp = item.import_decl;
            // Check if path is exactly "$std/ccp" (user program observability)
            if (std.mem.eql(u8, imp.path, "$std/ccp")) {
                has_ccp_import = true;
                break;
            }
        }
    }

    if (!has_ccp_import) {
        // Flag is set but feature not imported - user didn't declare intent
        return .{ .instrumented = .{ .ast = __koru_event_input.ast } };
    }

    const original_count = __koru_event_input.ast.items.len;
    const new_count = original_count + 1;

    // Create new items array (now allocated at runtime)
    const new_items = try allocator.alloc(Item, new_count);

    // Copy original items
    for (__koru_event_input.ast.items, 0..) |item, i| {
        new_items[i] = item;
    }

    // Inject self-contained CCP helper function
    const ccp_code =
        \\fn __ccp_emit_json(data: anytype) void {
        \\    const __ccp_std = @import("std");
        \\    var buffer: [8192]u8 = undefined;
        \\    var fba = __ccp_std.heap.FixedBufferAllocator.init(&buffer);
        \\    const allocator = fba.allocator();
        \\    var string = __ccp_std.ArrayList(u8).init(allocator);
        \\    defer string.deinit();
        \\    __ccp_std.json.stringify(data, .{}, string.writer()) catch return;
        \\    string.append('\n') catch return;
        \\    const stdout = __ccp_std.io.getStdOut().writer();
        \\    stdout.writeAll(string.items) catch {};
        \\}
    ;

    new_items[original_count] = .{ .host_line = .{
        .content = ccp_code,
        .location = .{ .line = 0, .column = 0, .file = "generated" },
        .module = "ccp_injected"
    } };

    // Create new SourceFile with injected code
    const new_ast = try allocator.create(SourceFile);
    new_ast.* = SourceFile{
        .items = new_items,
        .allocator = allocator,
    };

    return .{ .instrumented = .{ .ast = new_ast } };
    }
};

