// Helper: Join path segments with dots
const joinPath = struct {
    fn call(path: []const []const u8) []const u8 {
        if (path.len == 0) return "";
        if (path.len == 1) return path[0];
        var total_len: usize = path[0].len;
        var i: usize = 1;
        while (i < path.len) : (i += 1) {
            total_len += 1 + path[i].len;
        }
        var result: [256]u8 = undefined;
        var pos: usize = 0;
        @memcpy(result[pos..pos + path[0].len], path[0]);
        pos += path[0].len;
        i = 1;
        while (i < path.len) : (i += 1) {
            result[pos] = '.';
            pos += 1;
            @memcpy(result[pos..pos + path[i].len], path[i]);
            pos += path[i].len;
        }
        return result[0..pos];
    }
}.call;

// === USER COMPTIME HANDLERS ===
// These handlers execute at compile-time (Zig comptime) to transform the AST

// Comptime Handler Dispatcher
// Maps runtime handler names to actual handler calls
const ComptimeHandlerResult = union(enum) {
    none: void,
};

fn callComptimeHandler(name: []const u8, source_ast: *const SourceFile) ComptimeHandlerResult {
    _ = name;
    _ = source_ast;
    return .{ .none = {} };
}

// THE COMPILER PIPELINE COORDINATOR (hardcoded - not a Koru flow)
// See src/main.zig for explanation and to modify the pipeline
const compiler_coordinate_default = struct {
    pub const Input = struct { ast: *const SourceFile, allocator: std.mem.Allocator };
    pub const Output = union(enum) {
        coordinated: struct {
            ast: *const SourceFile,
            code: []const u8,
            metrics: []const u8,
        },
    };

    pub fn handler(__koru_event_input: Input) !Output {
        const allocator = __koru_event_input.allocator;
        // Execute the compilation pipeline as defined in compiler.coordinate.default:
        // 1. process_ccp_commands (reads AI commands from stdin when --ccp enabled)
        const ccp_result = compiler_passes_process_ccp_commands.handler(.{ .ast = __koru_event_input.ast });

        // 2. evaluate_comptime (executes comptime events to transform AST)
        const eval_result = try compiler_passes_evaluate_comptime.handler(.{ .ast = ccp_result.processed.ast, .allocator = allocator });

        // 3. check.structure (validates event/branch shapes)
        const structure_result = compiler_check_structure.handler(.{ .ast = eval_result.evaluated.ast });

        // 4. check.phantom.semantic (validates phantom type compatibility)
        const phantom_result = compiler_check_phantom_semantic.handler(.{ .ast = structure_result.valid.ast });

        // 5. optimize.fusion - Now happens at runtime in main(), not here
        const fusion_ast = phantom_result.valid.ast;

        // 6. inject_ccp (adds observability taps when --ccp + import ccp)
        const ccp_inject_result = try compiler_passes_inject_ccp.handler(.{ .ast = fusion_ast, .allocator = allocator });

        // 7. collect_build_requires (collects ~build.requires invocations)
        // TODO: Actually collect build requirements from AST
        const build_requires: []const u8 = &[_]u8{}; // Empty for now
        _ = build_requires;

        // 8. emit.zig (generates final Zig code)
        const emit_result = compiler_emit_zig.handler(.{ .ast = ccp_inject_result.instrumented.ast });

        // 9. emit_build_zig (generates build.zig file)
        // TODO: Actually generate build.zig from collected requirements

        // Note: Fusion now happens at runtime in main(), not in comptime pipeline
        const metrics = "Passes: 8 (process_ccp_commands, evaluate_comptime, check.structure, check.phantom.semantic, inject_ccp, collect_build_requires, emit.zig, emit_build_zig)";

        return .{ .coordinated = .{
            .ast = ccp_inject_result.instrumented.ast,
            .code = emit_result.emitted.code,
            .metrics = metrics,
        }};
    }
};
// Runtime emitter (moved from comptime to support fusion optimization)
const RuntimeEmitter = struct {
    pub fn emit(allocator: std.mem.Allocator, source_ast: *const SourceFile) ![]const u8 {
        const result = try compiler_coordinate_default.handler(.{ .ast = source_ast, .allocator = allocator });
        return result.coordinated.code;
    }
};

// Standard library import for the backend
const std = @import("std");
// === KORU BACKEND CODE GENERATOR ===
// This outputs the final Zig code generated by compiler.emit.zig

pub fn main() !void {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer {
        const leak_status = gpa.deinit();
        if (leak_status == .leak) {
            std.debug.print("Memory leak detected\n", .{});
        }
    }
    const allocator = gpa.allocator();

    // Get the output filename from argv (passed from koruc)
    const args = try std.process.argsAlloc(allocator);
    defer std.process.argsFree(allocator, args);

    // Default output names
    const emitted_file = "output_emitted.zig";
    const output_exe = if (args.len > 1) args[1] else "a.out";

    // Check if fusion is enabled
    const fusion_enabled = CompilerEnv.hasFlag("fusion");

    // Apply fusion optimization if enabled
    var final_ast: *const SourceFile = &PROGRAM_AST;
    var fused_ast: SourceFile = undefined;
    if (fusion_enabled) {
        fused_ast = try fusion_optimizer.optimize(allocator, &PROGRAM_AST);
        final_ast = &fused_ast;
    }
    defer if (fusion_enabled) fused_ast.deinit();

    // Generate code from AST (possibly fused)
    const generated_code = try RuntimeEmitter.emit(allocator, final_ast);

    // Write the generated code to a file
    const file = try std.fs.cwd().createFile(emitted_file, .{});
    defer file.close();
    try file.writeAll(generated_code);

    // Report what we generated
    const stdout = std.fs.File.stdout();
    var buf: [512]u8 = undefined;
    const msg = try std.fmt.bufPrint(&buf, "âś“ Generated {s} ({d} bytes)\n", .{emitted_file, generated_code.len});
    try stdout.writeAll(msg);

    // Now compile the emitted code
    var emit_path_buf: [256]u8 = undefined;
    const emit_path = try std.fmt.bufPrint(&emit_path_buf, "-femit-bin={s}", .{output_exe});
    const argv = [_][]const u8{ "zig", "build-exe", emitted_file, emit_path };
    const result = std.process.Child.run(.{
        .allocator = allocator,
        .argv = &argv,
    }) catch |err| {
        const stderr = std.fs.File.stderr();
        var err_buf: [512]u8 = undefined;
        const err_msg = try std.fmt.bufPrint(&err_buf, "âś— Failed to spawn zig compiler: {}\n", .{err});
        try stderr.writeAll(err_msg);
        std.process.exit(1);
    };
    defer allocator.free(result.stdout);
    defer allocator.free(result.stderr);

    const stdout2 = std.fs.File.stdout();
    var buf2: [512]u8 = undefined;
    if (result.term.Exited == 0) {
        const msg2 = try std.fmt.bufPrint(&buf2, "âś“ Compiled to {s}\n", .{output_exe});
        try stdout2.writeAll(msg2);
    } else {
        const msg2 = try std.fmt.bufPrint(&buf2, "âś— Compilation failed\n", .{});
        try stdout2.writeAll(msg2);
        if (result.stderr.len > 0) {
            var err_buf2: [65536]u8 = undefined;
            const err_msg2 = try std.fmt.bufPrint(&err_buf2, "Error: {s}\n", .{result.stderr});
            try std.fs.File.stderr().writeAll(err_msg2);
        }
        std.process.exit(1);
    }
}